users_db = {}

def mask_sensitive_data(data, mask_char='*', visible_chars=2):
    if not data or len(data) <= visible_chars:
        return mask_char * 8
    return data[:visible_chars] + mask_char * (len(data) - visible_chars)

def hash_for_logging(data):
    if not data:
        return "EMPTY"
    return hashlib.sha256(data.encode()).hexdigest()[:16]

def secure_log_login_attempt(username, password, email, ip_address, user_agent, success):
    masked_username = mask_sensitive_data(username, visible_chars=2)
    password_hash = hash_for_logging(password) if password else "EMPTY"
    masked_email = mask_sensitive_data(email, visible_chars=3) if email else "NONE"
    
    ip_parts = ip_address.split('.')
